// Build the top-N pairs string from screener output.
// Screener is already sorted by total volume desc; we clean + cap it.
const STABLE = new Set(['USDT','USDC','DAI','TUSD','FDUSD','BUSD','USDE','USD','PYUSD']);
const QUOTE = 'USDT';
const TOP_N = Number($('Set Bot Configuration').first().json.top_n) || 5;

let rows = $input.all().map(i => i.json);
// Unwrap if the API returned a single item wrapping an array
if (rows.length === 1 && Array.isArray(rows[0]?.data)) rows = rows[0].data;
if (rows.length === 1 && Array.isArray(rows[0]?.result)) rows = rows[0].result;
if (rows.length === 1 && Array.isArray(rows[0]?.data?.result)) rows = rows[0].data.result;
if (rows.length === 1 && Array.isArray(rows[0]?.items)) rows = rows[0].items;

const pairs = [];
for (const r of rows) {
  let sym = String(r.symbol || r.baseAsset || r.coin || r.ticker || '').toUpperCase().trim();
  if (!sym) continue;
  sym = sym.replace(/[_/-]?USDT$/, '');
  if (!sym || STABLE.has(sym)) continue;
  const pair = sym + '_' + QUOTE;
  if (!pairs.includes(pair)) pairs.push(pair);
  if (pairs.length >= TOP_N) break;
}

if (pairs.length === 0) {
  throw new Error('Screener returned no usable pairs — check filter/credentials/field names.');
}

return [{ json: { pairs: pairs.join(','), list: pairs, count: pairs.length } }];

